// Smart fuzzy search
function searchEmojis(query) {
  if (!query || !query.trim()) return EMOJIS;

  const terms = query.toLowerCase().trim().split(/\s+/);

  const results = EMOJIS.map(emoji => {
    const searchText = [emoji.n, emoji.e, ...emoji.a].join(' ').toLowerCase();
    let score = 0;

    for (const term of terms) {
      if (emoji.e === term) { score += 100; continue; }
      if (emoji.n.toLowerCase() === term) { score += 80; continue; }
      if (emoji.n.toLowerCase().startsWith(term)) { score += 60; continue; }
      if (emoji.n.toLowerCase().includes(term)) { score += 40; continue; }
      if (emoji.a.some(a => a === term)) { score += 50; continue; }
      if (emoji.a.some(a => a.startsWith(term))) { score += 35; continue; }
      if (emoji.a.some(a => a.includes(term))) { score += 20; continue; }
      if (searchText.includes(term)) { score += 10; continue; }
      // Fuzzy: chars in order
      let fi = 0, si = 0, matched = 0;
      while (fi < searchText.length && si < term.length) {
        if (searchText[fi] === term[si]) { matched++; si++; }
        fi++;
      }
      if (si === term.length) score += matched * 2;
    }

    return { ...emoji, score };
  })
  .filter(e => e.score > 0)
  .sort((a, b) => b.score - a.score);

  return results;
}

window.EMOJIS = EMOJIS;
window.EMOJI_CATEGORIES = EMOJI_CATEGORIES;
window.searchEmojis = searchEmojis;
